import { useEffect, useState } from "react";
import { bookService, userService } from "../services/api";
import MessageBanner from "../components/MessageBanner";

const DashboardPage = () => {
  const [booksCount, setBooksCount] = useState(0);
  const [usersCount, setUsersCount] = useState(0);
  const [availableCopies, setAvailableCopies] = useState(0);
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");

  useEffect(() => {
    const loadData = async () => {
      try {
        setError("");
        const [booksRes, usersRes] = await Promise.all([bookService.getAll(), userService.getAll()]);

        const books = booksRes.data || [];
        const users = usersRes.data || [];

        setBooksCount(books.length);
        setUsersCount(users.length);
        setAvailableCopies(books.reduce((sum, book) => sum + (book.availableCopies || 0), 0));
        setMessage("Dashboard loaded successfully");
      } catch (err) {
        setError(err.response?.data?.message || "Failed to load dashboard");
      }
    };

    loadData();
  }, []);

  return (
    <div>
      <h2 className="text-2xl font-semibold mb-6">Dashboard</h2>
      <MessageBanner message={message} />
      <MessageBanner message={error} variant="error" />
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
        <div className="bg-white p-5 rounded-lg shadow">
          <p className="text-sm text-gray-500">Total Books</p>
          <p className="text-3xl font-bold text-slate-800">{booksCount}</p>
        </div>
        <div className="bg-white p-5 rounded-lg shadow">
          <p className="text-sm text-gray-500">Registered Users</p>
          <p className="text-3xl font-bold text-slate-800">{usersCount}</p>
        </div>
        <div className="bg-white p-5 rounded-lg shadow">
          <p className="text-sm text-gray-500">Available Copies</p>
          <p className="text-3xl font-bold text-slate-800">{availableCopies}</p>
        </div>
      </div>
    </div>
  );
};

export default DashboardPage;
